sql:
SELECT country_name
FROM countries
WHERE population > 50000000 AND area > 300000;

external_knowledge:
- 'stand as the giants among their peers' refers to the largest cities in terms of population;
- 'exceeding 500,000 souls' refers to a population greater than 500,000;
- 'New York' is a state in the United States.
